const seenUrls = new Set();
const allOrganicResults = [];
for (const item of $input.all()) {
  const results = item.json.organic_results || [];
  for (const result of results) {
    if (result.link && !seenUrls.has(result.link)) {
      seenUrls.add(result.link);
      allOrganicResults.push(result);
    }
  }
}
if (allOrganicResults.length === 0) {
  return [{ json: { error: 'No organic results found', searchCompleted: true } }];
}
return allOrganicResults.map(result => ({ json: result }));

const notionResults = $input.all();
const articleData = $('Loop Over Items').item.json;
const isDuplicate = notionResults.some(item =>
  item.json && item.json.id && typeof item.json.id === 'string' && item.json.id.length > 0
);
return [{ json: { ...articleData, isDuplicate } }];

