const articleData = $('Is New Article?').item.json;
const summary = $json.message?.content || $json.content || $json.text || '';
return [{ json: { ...articleData, content: summary.trim() } }];

const articleData = $('Extract Summary').item.json;
const aiResponse = $json.message?.content || $json.content || $json.text || '{}';
let evaluation;
try {
  const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);
  evaluation = JSON.parse(jsonMatch ? jsonMatch[0] : aiResponse);
} catch (e) {
  evaluation = { credibility: 3, accuracy: 3, relevance: 3, overall_score: 3, evaluation_notes: 'Evaluation parsing failed - using default scores', should_include: true };
}
return { json: { ...articleData, credibility: evaluation.credibility || 3, accuracy: evaluation.accuracy || 3, relevance: evaluation.relevance || 3, overall_score: evaluation.overall_score || 3, evaluation_notes: evaluation.evaluation_notes || 'No notes', should_include: evaluation.should_include !== false } };

const articleData = $('Parse Evaluation').item.json;
const aiResponse = $json.message?.content || $json.content || $json.text || '{}';
let classification;
try {
  const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);
  classification = JSON.parse(jsonMatch ? jsonMatch[0] : aiResponse);
} catch (e) {
  classification = { primary_theme: 'General Innovation', themes: ['General Innovation'], summary: '' };
}
const validThemes = ['Aerodynamics', 'Power Unit', 'Chassis & Suspension', 'Electronics & Software', 'Materials & Manufacturing', 'Testing & Simulation', 'Regulations & Compliance', 'Race Strategy Tech', 'Driver Interface', 'Safety Innovations', 'Cooling Systems', 'Data Analysis', 'Team Collaboration', 'Sustainability', 'General Innovation'];
const themes = (classification.themes || []).filter(t => validThemes.includes(t)).slice(0, 5);
if (themes.length === 0) themes.push('General Innovation');
const themesString = themes.join(',');
return { json: { title: articleData.title || 'Untitled Article', url: articleData.link && articleData.link.trim() !== '' ? articleData.link : 'https://unknown.com', source: articleData.source || 'Unknown', publication_date: articleData.date, summary: $('Extract Summary').first().json.content || 'No summary available', primary_theme: validThemes.includes(classification.primary_theme) ? classification.primary_theme : 'General Innovation', themes: themesString, credibility: articleData.credibility || 3, accuracy: articleData.accuracy || 3, relevance: articleData.relevance || 3, overall_score: articleData.overall_score || 3, evaluation_notes: articleData.evaluation_notes || '', implications: $('Extract Implication').first().json.implications || '',
    analyzed_on: new Date().toISOString() } };

// ============================================================
// NODE NAME: Validate Notion Fields
// POSITION: Between "Prepare Notion Data" and "Save to Notion"
// ============================================================

const data = $input.item.json;

// ── Helpers ──────────────────────────────────────────────────

function truncateChars(str, max, suffix = '...') {
  if (!str) return '';
  str = String(str);
  return str.length > max ? str.slice(0, max - suffix.length) + suffix : str;
}

function countWords(str) {
  if (!str) return 0;
  return str.trim().split(/\s+/).filter(Boolean).length;
}

function truncateWords(str, maxWords) {
  if (!str) return '';
  const words = str.trim().split(/\s+/);
  if (words.length <= maxWords) return str;
  return words.slice(0, maxWords).join(' ') + '...';
}

function clampScore(val, min = 0, max = 5) {
  const n = parseFloat(val);
  if (isNaN(n)) return 3; // default fallback
  return Math.min(max, Math.max(min, n));
}

function formatDate(raw) {
  if (!raw) return new Date().toISOString().split('T')[0]; // today as YYYY-MM-DD (Notion default)
  // Already YYYY-MM-DD
  if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) return raw;
  // DD/MM/YYYY → YYYY-MM-DD
  const dmyMatch = raw.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (dmyMatch) return `${dmyMatch[3]}-${dmyMatch[2]}-${dmyMatch[1]}`;
  // Fallback: try native parse
  const d = new Date(raw);
  if (!isNaN(d)) return d.toISOString().split('T')[0];
  return new Date().toISOString().split('T')[0];
}

function normalizeCategory(str) {
  if (!str) return 'GENERAL INNOVATION';
  return truncateChars(str.toUpperCase(), 25, '.');
}

// ── Field Limits (from NOTION_INPUT_GUIDE.md) ────────────────
const TITLE_MAX_CHARS        = 90;
const CATEGORY_MAX_CHARS     = 25;
const SUMMARY_RELINFO_MAX_W  = 220; // hard word limit (Summary + Relevant Info combined)
const SCORE_MIN              = 0;
const SCORE_MAX              = 5;

// ── 1. Title ─────────────────────────────────────────────────
const title = truncateChars(data.title || 'Untitled Article', TITLE_MAX_CHARS, '...');

// ── 2. Category (mapped from primary_theme) ──────────────────
const THEME_TO_CATEGORY = {
  'Aerodynamics':            'AERODYNAMICS',
  'Power Unit':              'GENERAL INNOVATION',
  'Chassis & Suspension':    'GENERAL INNOVATION',
  'Electronics & Software':  'GENERAL INNOVATION',
  'Materials & Manufacturing':'GENERAL INNOVATION',
  'Testing & Simulation':    'TESTING & SIMULATION',
  'Regulations & Compliance':'REGULATIONS',
  'Race Strategy Tech':      'COMPETITIVE MOVE',
  'Driver Interface':        'GENERAL INNOVATION',
  'Safety Innovations':      'GENERAL INNOVATION',
  'Cooling Systems':         'COOLING SYSTEMS',
  'Data Analysis':           'GENERAL INNOVATION',
  'Team Collaboration':      'M&A',
  'Sustainability':          'GENERAL INNOVATION',
  'General Innovation':      'GENERAL INNOVATION',
};

const rawTheme    = data.primary_theme || 'General Innovation';
const rawCategory = THEME_TO_CATEGORY[rawTheme] || normalizeCategory(rawTheme);
const category    = normalizeCategory(rawCategory);

// ── 3. Summary + Relevant Info (shared 220-word budget) ──────
const summaryRaw   = String(data.summary || '');
const relInfoRaw   = String(data.relevant_info || '');

const combinedWordCount = countWords(summaryRaw) + countWords(relInfoRaw);

let summary      = summaryRaw;
let relevant_info = relInfoRaw;

if (combinedWordCount > SUMMARY_RELINFO_MAX_W) {
  // Distribute budget proportionally between the two fields
  const summaryWords   = countWords(summaryRaw);
  const relInfoWords   = countWords(relInfoRaw);
  const total          = summaryWords + relInfoWords || 1;

  const summaryBudget  = Math.floor((summaryWords / total)  * SUMMARY_RELINFO_MAX_W);
  const relInfoBudget  = SUMMARY_RELINFO_MAX_W - summaryBudget;

  summary       = truncateWords(summaryRaw,  summaryBudget);
  relevant_info = truncateWords(relInfoRaw,  relInfoBudget);
}

// ── 4. Publication Date ───────────────────────────────────────
const publication_date = formatDate(data.publication_date || data.date || null);

// ── 5. Scores (clamped 0–5) ───────────────────────────────────
const credibility   = clampScore(data.credibility);
const accuracy      = clampScore(data.accuracy);
const relevance     = clampScore(data.relevance);
const overall_score = clampScore(data.overall_score);

// ── 6. URL (passthrough) ──────────────────────────────────────
const url = data.url || data.link || 'https://unknown.com';

// ── Output ────────────────────────────────────────────────────
return {
  json: {
    // Validated fields
    title,
    category,
    summary,
    relevant_info,
    publication_date,
    credibility,
    accuracy,
    relevance,
    overall_score,
    url,

    // Passthrough (untouched)
    source:           data.source           || '',
    themes:           data.themes           || '',
    primary_theme:    data.primary_theme    || '',
    evaluation_notes: data.evaluation_notes || '',
    implications:     data.implications     || '',
    analyzed_on:      data.analyzed_on      || new Date().toISOString(),

    // Debug info
    _validation: {
      title_chars:           title.length,
      category_chars:        category.length,
      combined_word_count:   Math.min(combinedWordCount, SUMMARY_RELINFO_MAX_W),
      was_truncated:         combinedWordCount > SUMMARY_RELINFO_MAX_W,
    }
  }
};

const articleData = $('Extract Summary').item.json;
const implications = $json.message?.content || $json.content || $json.text || '';
return [{ json: { ...articleData, implications: implications.trim() } }];
